import { useNavigate } from 'react-router-dom';

export default function Footer() {
  const navigate = useNavigate();
  const s = {
    footer: { background: '#030e1e', padding: '70px 60px 30px', borderTop: '1px solid rgba(212,160,23,0.25)', fontFamily: "'Jost', sans-serif" },
    grid: { display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1.5fr', gap: 50, marginBottom: 60 },
    title: { fontSize: '0.7rem', letterSpacing: 3, textTransform: 'uppercase', color: '#D4A017', fontWeight: 600, marginBottom: 20 },
    link: { color: 'rgba(255,255,255,0.45)', fontSize: '0.82rem', cursor: 'pointer', display: 'block', marginBottom: 10, textDecoration: 'none' },
    contact: { display: 'flex', gap: 10, marginBottom: 12 },
    bottom: { borderTop: '1px solid rgba(212,160,23,0.15)', paddingTop: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
    copy: { fontSize: '0.75rem', color: 'rgba(255,255,255,0.3)' },
  };

  return (
    <footer style={s.footer}>
      <div style={s.grid}>
        <div>
          <div style={{ fontFamily: "'Playfair Display', serif", fontSize: '1.6rem', fontWeight: 700, color: '#D4A017' }}>✈ Skylark</div>
          <div style={{ fontSize: '0.6rem', letterSpacing: 4, textTransform: 'uppercase', color: 'rgba(255,255,255,0.3)' }}>Tour & Travels</div>
          <p style={{ fontSize: '0.82rem', color: 'rgba(255,255,255,0.4)', lineHeight: 1.8, marginTop: 16 }}>
            "We Don't Just Plan Trips, We Create Memories." Your trusted Edmonton travel partner.
          </p>
          <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
            {['📷', '👥', '💬', '🎵', '▶️', '💼'].map((icon, i) => (
              <a key={i} href="#" style={{ width: 36, height: 36, border: '1px solid rgba(212,160,23,0.25)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'rgba(255,255,255,0.5)', textDecoration: 'none', fontSize: '1rem' }}>{icon}</a>
            ))}
          </div>
        </div>
        <div>
          <div style={s.title}>Quick Links</div>
          {[['Home', '/'], ['Packages', '/packages'], ['Flights', '/flights'], ['Contact', '/contact']].map(([l, p]) => (
            <span key={l} onClick={() => navigate(p)} style={s.link}>{l}</span>
          ))}
        </div>
        <div>
          <div style={s.title}>Services</div>
          {['Tour Packages', 'Flight Assistance', 'Hotel Booking', 'Visa Assistance', 'Travel Insurance', 'Honeymoon Packages'].map(s2 => (
            <span key={s2} style={{ ...s.link, cursor: 'default' }}>{s2}</span>
          ))}
        </div>
        <div>
          <div style={s.title}>Contact</div>
          <div style={s.contact}><span style={{ color: '#D4A017' }}>📞</span><div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.45)', lineHeight: 1.6 }}>+1 (587) 774-2020<br />+1 (825) 419-1125</div></div>
          <div style={s.contact}><span style={{ color: '#D4A017' }}>✉️</span><div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.45)' }}>manik@travelskylark.com</div></div>
          <div style={s.contact}><span style={{ color: '#D4A017' }}>📍</span><div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.45)', lineHeight: 1.5 }}>9252 34 Ave NW #202<br />Edmonton, AB T6N 1C9</div></div>
        </div>
      </div>
      <div style={s.bottom}>
        <div style={s.copy}>© 2026 <span style={{ color: '#D4A017' }}>Skylark Tour & Travels</span>. All Rights Reserved.</div>
        <div style={s.copy}>Built with ♥ for unforgettable journeys</div>
      </div>
    </footer>
  );
}
